 219→### Task 3: Create db/migrations.rs — Versioned Migration Runner
 220→
 221→**Files:**
 222→- Create: `src/factory/db/migrations.rs`
 223→
 224→**Step 1: Write the migration runner**
 225→
 226→```rust
 227→use anyhow::{Context, Result};
 228→use libsql::Connection;
 229→
 230→const MIGRATIONS: &[(i64, &str)] = &[
 231→    (1, include_str!("migrations/001_initial.sql")),
 232→    (2, include_str!("migrations/002_github_integration.sql")),
 233→    (3, include_str!("migrations/003_agent_teams.sql")),
 234→    (4, include_str!("migrations/004_settings.sql")),
 235→    (5, include_str!("migrations/005_orchestrator_state.sql")),
 236→    (6, include_str!("migrations/006_soft_deletes_and_indexes.sql")),
 237→];
 238→
 239→/// Run all pending migrations. Uses PRAGMA user_version to track state.
 240→pub async fn run_migrations(conn: &Connection) -> Result<()> {
 241→    let current_version = get_user_version(conn).await?;
 242→
 243→    // Bootstrap: if tables exist but user_version is 0 (pre-migration DB),
 244→    // detect existing schema and set version accordingly.
 245→    if current_version == 0 {
 246→        let bootstrapped = bootstrap_existing_db(conn).await?;
 247→        if bootstrapped > 0 {
 248→            tracing::info!("Bootstrapped existing database at migration version {bootstrapped}");
 249→            return run_from_version(conn, bootstrapped).await;
 250→        }
 251→    }
 252→
 253→    run_from_version(conn, current_version).await
 254→}
 255→
 256→async fn run_from_version(conn: &Connection, current: i64) -> Result<()> {
 257→    for (version, sql) in MIGRATIONS.iter() {
 258→        if *version <= current {
 259→            continue;
 260→        }
 261→        tracing::info!("Running migration {version}...");
 262→        conn.execute_batch(sql)
 263→            .await
 264→            .with_context(|| format!("Failed to run migration {version}"))?;
 265→        set_user_version(conn, *version).await?;
 266→    }
 267→    Ok(())
 268→}
 269→
 270→async fn get_user_version(conn: &Connection) -> Result<i64> {
 271→    let mut rows = conn.query("PRAGMA user_version", ()).await
 272→        .context("Failed to query user_version")?;
 273→    match rows.next().await? {
 274→        Some(row) => Ok(row.get::<i64>(0)?),
 275→        None => Ok(0),
 276→    }
 277→}
 278→
 279→async fn set_user_version(conn: &Connection, version: i64) -> Result<()> {
 280→    conn.execute(&format!("PRAGMA user_version = {version}"), ())
 281→        .await
 282→        .with_context(|| format!("Failed to set user_version to {version}"))?;
 283→    Ok(())
 284→}
 285→
 286→/// Detect if this is a pre-migration database (tables exist but user_version=0).
 287→/// Returns the migration version that matches the current schema, or 0 if empty.
 288→async fn bootstrap_existing_db(conn: &Connection) -> Result<i64> {
 289→    // Check if the core 'projects' table exists
 290→    let mut rows = conn
 291→        .query(
 292→            "SELECT name FROM sqlite_master WHERE type='table' AND name='projects'",
 293→            (),
 294→        )
 295→        .await?;
 296→
 297→    if rows.next().await?.is_none() {
 298→        return Ok(0); // Fresh database
 299→    }
 300→
 301→    // Tables exist — determine how far the schema has evolved.
 302→    // Check for settings table (migration 4)
 303→    let mut rows = conn
 304→        .query(
 305→            "SELECT name FROM sqlite_master WHERE type='table' AND name='settings'",
 306→            (),
 307→        )
 308→        .await?;
 309→    if rows.next().await?.is_some() {
 310→        set_user_version(conn, 4).await?;
 311→        return Ok(4);
 312→    }
 313→
 314→    // Check for agent_teams table (migration 3)
 315→    let mut rows = conn
 316→        .query(
 317→            "SELECT name FROM sqlite_master WHERE type='table' AND name='agent_teams'",
 318→            (),
 319→        )
 320→        .await?;
 321→    if rows.next().await?.is_some() {
 322→        set_user_version(conn, 3).await?;
 323→        return Ok(3);
 324→    }
 325→
 326→    // Check for github_repo column (migration 2)
 327→    let mut rows = conn
 328→        .query("PRAGMA table_info(projects)", ())
 329→        .await?;
 330→    while let Some(row) = rows.next().await? {
 331→        let name: String = row.get(1)?;
 332→        if name == "github_repo" {
 333→            set_user_version(conn, 2).await?;
 334→            return Ok(2);
 335→        }
 336→    }
 337→
 338→    // Base tables only (migration 1)
 339→    set_user_version(conn, 1).await?;
 340→    Ok(1)
 341→}
