 539→### Task 5: Create db/settings.rs — KV Store Operations
 540→
 541→Start with the simplest domain module to establish the pattern.
 542→
 543→**Files:**
 544→- Create: `src/factory/db/settings.rs`
 545→
 546→**Step 1: Write settings operations**
 547→
 548→Port from current `db.rs:1337-1367`. Change `&self` (FactoryDb) to take `conn: &Connection`. Change sync rusqlite calls to async libsql calls.
 549→
 550→Key API differences:
 551→- `rusqlite`: `conn.query_row(sql, params![key], |row| row.get(0))` (sync, closure-based)
 552→- `libsql`: `conn.query(sql, [key]).await?` then `rows.next().await?` then `row.get(0)?` (async, iterator-based)
 553→
 554→```rust
 555→use anyhow::{Context, Result};
 556→use libsql::Connection;
 557→
 558→pub async fn get_setting(conn: &Connection, key: &str) -> Result<Option<String>> {
 559→    let mut rows = conn
 560→        .query("SELECT value FROM settings WHERE key = ?1", [key])
 561→        .await
 562→        .context("Failed to query setting")?;
 563→    match rows.next().await? {
 564→        Some(row) => Ok(Some(row.get::<String>(0)?)),
 565→        None => Ok(None),
 566→    }
 567→}
 568→
 569→pub async fn set_setting(conn: &Connection, key: &str, value: &str) -> Result<()> {
 570→    conn.execute(
 571→        "INSERT INTO settings (key, value, updated_at) VALUES (?1, ?2, datetime('now'))
 572→         ON CONFLICT(key) DO UPDATE SET value = ?2, updated_at = datetime('now')",
 573→        libsql::params![key, value],
 574→    )
 575→    .await
 576→    .context("Failed to set setting")?;
 577→    Ok(())
 578→}
 579→
 580→pub async fn delete_setting(conn: &Connection, key: &str) -> Result<()> {
 581→    conn.execute("DELETE FROM settings WHERE key = ?1", [key])
 582→        .await
 583→        .context("Failed to delete setting")?;
 584→    Ok(())
 585→}
