1049→**Step 2: Replace event batching (lines 354-414)**
1050→
1051→Old pattern: `lock_sync()` + sync `create_agent_event()` in a loop.
1052→
1053→New pattern with time-based flushing:
1054→```rust
1055→let db_writer = self.db.clone();
1056→let writer_task = tokio::spawn(async move {
1057→    let mut batch = Vec::new();
1058→    let flush_interval = Duration::from_secs(2);
1059→
1060→    loop {
1061→        tokio::select! {
1062→            event = event_rx.recv() => {
1063→                match event {
1064→                    Some(e) => {
1065→                        batch.push(e);
1066→                        // Drain additional ready events
1067→                        while batch.len() < 25 {
1068→                            match event_rx.try_recv() {
1069→                                Ok(e) => batch.push(e),
1070→                                Err(_) => break,
1071→                            }
1072→                        }
1073→                        if batch.len() >= 25 {
1074→                            flush_events(&db_writer, &mut batch).await;
1075→                        }
1076→                    }
1077→                    None => {
1078→                        // Channel closed — flush remaining and exit
1079→                        flush_events(&db_writer, &mut batch).await;
1080→                        break;
1081→                    }
1082→                }
1083→            }
1084→            _ = tokio::time::sleep(flush_interval) => {
1085→                if !batch.is_empty() {
1086→                    flush_events(&db_writer, &mut batch).await;
1087→                }
1088→            }
1089→        }
1090→    }
1091→});
1092→```
1093→
1094→Add helper:
1095→```rust
1096→async fn flush_events(
1097→    db: &DbHandle,
1098→    batch: &mut Vec<(i64, String, String, Option<serde_json::Value>)>,
1099→) {
1100→    for (task_id, event_type, content, metadata) in batch.drain(..) {
1101→        if let Err(e) = db.create_agent_event(task_id, &event_type, &content, metadata.as_ref()).await {
1102→            eprintln!("[agent] Failed to write event: {e:#}");
1103→        }
1104→    }
1105→}
1106→```
